def cwe_078_0_v4_tool(dirpath, log_path=None, report_url=None):
    import os
    import logging

    try:
        # Check if the directory exists and can be accessed
        if os.path.isdir(dirpath) and os.access(dirpath, os.R_OK):
            result = "\n".join([f for f in os.listdir(dirpath)])  # Return detailed listing of files in the directory

            # Logging or external interaction based on provided parameters
            if log_path is not None:
                logging.basicConfig(filename=log_path, level=logging.INFO)
                logging.info('Directory exists and accessible')
